-- Kinora: products table + access control + seed.
-- Run in Supabase → SQL Editor → New query → Run. Safe to re-run (idempotent).
--
-- The storefront (anon key) reads ONLY active products. Only admins (is_admin())
-- can insert / update / delete. Mirrors the orders/vouchers security model.

create table if not exists public.products (
  id           integer primary key,
  type         text not null,                 -- 'haori' | 'kimono'
  lbl          text default '',               -- '' | 'Ново' | 'Винтидж'
  cat          text,
  name         text not null,
  sub          text,
  price        numeric not null default 0,
  colors       jsonb default '[]'::jsonb,
  description  text default '',
  sizes        jsonb default '[]'::jsonb,
  measure      jsonb,                          -- {back,length,sleeve} or null
  details      jsonb default '[]'::jsonb,
  bg           text default '#0c0608',
  acc          text default '#c4a464',
  img          text default '',
  is_active    boolean not null default true,
  sort_order   integer default 0,
  created_at   timestamptz not null default now()
);

alter table public.products enable row level security;

-- Storefront: anyone may read ACTIVE products only.
drop policy if exists "public read active products" on public.products;
create policy "public read active products" on public.products
  for select to anon, authenticated using (is_active = true);

-- Admins: full read + write (incl. hidden products).
drop policy if exists "admins read all products" on public.products;
create policy "admins read all products" on public.products
  for select to authenticated using (public.is_admin());

drop policy if exists "admins insert products" on public.products;
create policy "admins insert products" on public.products
  for insert to authenticated with check (public.is_admin());

drop policy if exists "admins update products" on public.products;
create policy "admins update products" on public.products
  for update to authenticated using (public.is_admin()) with check (public.is_admin());

drop policy if exists "admins delete products" on public.products;
create policy "admins delete products" on public.products
  for delete to authenticated using (public.is_admin());

-- Keep the id sequence ahead of seeded ids so new inserts don't collide.
create sequence if not exists public.products_id_seq owned by public.products.id;
alter table public.products alter column id set default nextval('public.products_id_seq');

